import React from 'react'
import { TSubTitle } from '../../Layout/app/Types';

const SubTitle = ({title,href,count,icon}:TSubTitle) => {
  return (
    <div className='SubTitle'>
        <div>
       {icon}
           {title} 
        </div>
        <div>
            <a href='/'>
            See more{count}
            </a>
        </div>

    </div>
  )
}

export default SubTitle
